17	#include "libc.h"
18	#include "memory_map.h"
19	#include "slab.h"
20	#include "thread.h"
21	#include "trap.h"
22	#include "vm_address_space.h"
23	#include "vm_cache.h"
24	#include "vm_page.h"
25	
26	static struct vm_address_space kernel_address_space;
27	
28	MAKE_SLAB(address_space_slab, struct vm_address_space)
29	
30	static int soft_fault(struct vm_address_space *space,
31	                      const struct vm_area *area, unsigned int address,
32	                      int is_store);
33	
34	struct vm_address_space *get_kernel_address_space(void)
35	{
36	    return &kernel_address_space;
37	}
38	
39	void vm_address_space_init(struct vm_translation_map *translation_map)
40	{
41	    int i;
42	    struct vm_area_map *amap = &kernel_address_space.area_map;
43	
44	    kernel_address_space.translation_map = translation_map;
45	    init_rwlock(&kernel_address_space.mut);
46	    init_area_map(amap, KERNEL_BASE, 0xffffffff);
47	    create_vm_area(amap, KERNEL_BASE, KERNEL_END - KERNEL_BASE, PLACE_EXACT,
48	                   "kernel", AREA_WIRED | AREA_WRITABLE | AREA_EXECUTABLE);
49	    create_vm_area(amap, PHYS_MEM_ALIAS, memory_size, PLACE_EXACT,
50	                   "memory alias", AREA_WIRED | AREA_WRITABLE);
51	    create_vm_area(amap, KERNEL_HEAP_BASE, KERNEL_HEAP_SIZE, PLACE_EXACT,
52	                   "kernel_heap", AREA_WIRED | AREA_WRITABLE);
53	    create_vm_area(amap, DEVICE_REG_BASE, 0x10000, PLACE_EXACT,
54	                   "device registers", AREA_WIRED | AREA_WRITABLE);
55	    for (i = 0; i < 4; i++)
56	    {
57	        create_vm_area(amap, INITIAL_KERNEL_STACKS + i * KERNEL_STACK_SIZE,
58	                       KERNEL_STACK_SIZE, PLACE_EXACT, "kernel stack",
59	                       AREA_WIRED | AREA_WRITABLE);
60	    }
61	}
62	
63	struct vm_address_space *create_address_space(void)
64	{
65	    struct vm_address_space *space;
66	
67	    space = slab_alloc(&address_space_slab);
68	    init_area_map(&space->area_map, PAGE_SIZE, KERNEL_BASE - 1);
69	    space->translation_map = create_translation_map();
70	    init_rwlock(&space->mut);
71	
72	    return space;
73	}
74	
75	// No locking, because at this point only one thread (grim reaper) should
76	// be referencing this address space
77	void destroy_address_space(struct vm_address_space *space)
78	{
79	    struct vm_area *area;
80	
81	    VM_DEBUG("destroy_address_space %p\n", space);
82	    while ((area = first_area(&space->area_map)) != 0)
83	    {
84	        VM_DEBUG("destroy area %s\n", area->name);
85	        if (area->cache)
86	            dec_cache_ref(area->cache);
87	
88	        destroy_vm_area(area);
89	    }
90	
91	    destroy_translation_map(space->translation_map);
92	}
93	
94	struct vm_area *create_area(struct vm_address_space *space, unsigned int address,
95	                            unsigned int size, enum placement place,
96	                            const char *name, unsigned int flags,
97	                            struct vm_cache *cache, unsigned int cache_offset)
98	{
99	    struct vm_area *area;
100	    unsigned int fault_addr;
101	
102	    // Anonymous area, create a cache if non is specified.
103	    if (cache == 0)
104	        cache = create_vm_cache(0);
105	    else
106	        inc_cache_ref(cache);
107	
108	    rwlock_lock_write(&space->mut);
109	    area = create_vm_area(&space->area_map, address, size, place, name, flags);
110	    if (area == 0)
111	    {
112	        kprintf("create area failed\n");
113	        goto error1;
114	    }
115	
116	    area->cache = cache;
117	    area->cache_offset = cache_offset;
118	    area->cache_length = size;
119	    if (flags & AREA_WIRED)
120	    {
121	        for (fault_addr = area->low_address; fault_addr < area->high_address;
122	                fault_addr += PAGE_SIZE)
123	        {
124	            if (!soft_fault(space, area, fault_addr, 1))
125	                panic("create_area: soft fault failed");
126	        }
127	    }
128	
129	error1:
130	    rwlock_unlock_write(&space->mut);
131	
132	    return area;
133	}
134	
135	// This area is wired by default and does not take page faults.
136	// The pages for this area should already have been allocated: this will not
137	// mark them as such. The area created by this will not be backed by a
138	// vm_cache or vm_backing_store.
139	struct vm_area *map_contiguous_memory(struct vm_address_space *space, unsigned int address,
140	                                      unsigned int size, enum placement place,
141	                                      const char *name, unsigned int area_flags,
142	                                      unsigned int phys_addr)
143	{
144	    struct vm_area *area;
145	    unsigned int page_flags;
146	    unsigned int offset;
147	
148	    area_flags |= AREA_WIRED;
149	
150	    rwlock_lock_write(&space->mut);
151	    area = create_vm_area(&space->area_map, address, size, place, name, area_flags);
152	    if (area == 0)
153	    {
154	        kprintf("create area failed\n");
155	        goto error1;
156	    }
157	
158	    area->cache = 0;
159	
160	    page_flags = PAGE_PRESENT;
161	
162	    // We do not do dirty page tracking on these areas, as this is expected to
163	    // be device memory. Mark pages writable by default if the area is writable.
164	    if ((area_flags & AREA_WRITABLE) != 0)
165	        page_flags |= PAGE_WRITABLE;
166	
167	    if (area->flags & AREA_EXECUTABLE)
168	        page_flags |= PAGE_EXECUTABLE;
169	
170	    if (space == &kernel_address_space)
171	        page_flags |= PAGE_SUPERVISOR | PAGE_GLOBAL;
172	
173	    // Map the pages
174	    for (offset = 0; offset < size; offset += PAGE_SIZE)
175	    {
176	        vm_map_page(space->translation_map, area->low_address + offset,
177	                    (phys_addr + offset) | page_flags);
178	    }
179	
180	error1:
181	    rwlock_unlock_write(&space->mut);
182	
183	    return area;
184	}
185	
186	void destroy_area(struct vm_address_space *space, struct vm_area *area)
187	{
188	    struct vm_cache *cache;
189	    unsigned int va;
190	    unsigned int ptentry;
191	
192	    rwlock_lock_write(&space->mut);
193	    cache = area->cache;
194	
195	    // Unmap all pages in this area
196	    for (va = area->low_address; va < area->high_address; va += PAGE_SIZE)
197	    {
198	        ptentry = query_translation_map(space->translation_map, va);
199	        if ((ptentry & PAGE_PRESENT) != 0)
200	        {
201	            VM_DEBUG("destroy_area: decrementing page ref for va %08x pa %08x\n",
202	                    va, PAGE_ALIGN(ptentry));
203	            dec_page_ref(pa_to_page(ptentry));
204	        }
205	    }
206	
207	    destroy_vm_area(area);
208	    rwlock_unlock_write(&space->mut);
209	    if (cache)
210	        dec_cache_ref(cache);
211	}
212	
213	int handle_page_fault(unsigned int address, int is_store)
214	{
215	    struct vm_address_space *space;
216	    const struct vm_area *area;
217	    int result = 0;
218	
219	    if (address >= KERNEL_BASE)
220	        space = &kernel_address_space;
221	    else
222	        space = current_thread()->proc->space;
223	
224	    rwlock_lock_read(&space->mut);
225	    area = lookup_area(&space->area_map, address);
226	    if (area == 0)
227	    {
228	        result = 0;
229	        goto error1;
230	    }
231	
232	    result = soft_fault(space, area, address, is_store);
233	
234	error1:
235	    rwlock_unlock_read(&space->mut);
236	
237	    return result;
238	}
239	
240	//
241	// This is always called with the address space lock held, so the area is
242	// guaranteed not to change. Returns 1 if it sucessfully satisfied the fault, 0
243	// if it failed for some reason.
244	//
245	static int soft_fault(struct vm_address_space *space, const struct vm_area *area,
246	                      unsigned int address, int is_store)
247	{
248	    int got;
249	    unsigned int page_flags;
250	    struct vm_page *source_page;
251	    struct vm_page *dummy_page = 0;
252	    unsigned int area_offset;
253	    unsigned int cache_offset;
254	    struct vm_cache *cache;
255	    int old_flags;
256	    int is_cow_page = 0;
257	    int size_to_read;
258	
259	    VM_DEBUG("soft fault va %08x %s\n", address, is_store ? "store" : "load");
260	
261	    // XXX check area protections and fail if this shouldn't be allowed
262	    if (is_store && (area->flags & AREA_WRITABLE) == 0)
263	    {
264	        kprintf("store to read only area %s @%08x\n", area->name, address);
265	        return 0;
266	    }
267	
268	    area_offset = PAGE_ALIGN(address - area->low_address);
269	    cache_offset = PAGE_ALIGN(area_offset + area->cache_offset);
270	    old_flags = disable_interrupts();
271	    lock_vm_cache();
272	    assert(area->cache);
273	
274	    for (cache = area->cache; cache; cache = cache->source)
275	    {
276	        VM_DEBUG("searching in cache %p\n", cache);
277	        source_page = lookup_cache_page(cache, cache_offset);
278	        if (source_page)
279	            break;
280	
281	        if (cache->file)
282	        {
283	            VM_DEBUG("reading page from file\n");
284	
285	            // Read the page from this cache.
286	            source_page = vm_allocate_page();
287	
288	            // Insert the page first so, if a collided fault occurs, it will not
289	            // load a different page (the vm cache lock protects the busy bit)
290	            source_page->busy = 1;
291	            insert_cache_page(cache, cache_offset, source_page);
292	            unlock_vm_cache();
293	            restore_interrupts(old_flags);
294	
295	            if (area->cache_length < area_offset
296	                || area->cache_length - area_offset < PAGE_SIZE)
297	                size_to_read = area->cache_length - area_offset;
298	            else
299	                size_to_read = PAGE_SIZE;
300	
301	            if (size_to_read > 0)
302	            {
303	                got = read_file(cache->file, cache_offset,
304	                                (void*) PA_TO_VA(page_to_pa(source_page)), size_to_read);
305	                if (got < 0)
306	                {
307	                    kprintf("failed to read from file\n");
308	                    dec_page_ref(source_page);
309	                    if (dummy_page != 0)
310	                    {
311	                        disable_interrupts();
312	                        lock_vm_cache();
313	                        remove_cache_page(dummy_page);
314	                        unlock_vm_cache();
315	                        restore_interrupts(old_flags);
316	                        dec_page_ref(dummy_page);
317	                    }
318	
319	                    return 0;
320	                }
321	            }
322	            else
323	                size_to_read = 0;
324	
325	            // For BSS, clear out data past the end of the file
326	            if (size_to_read < PAGE_SIZE)
327	            {
328	                memset((char*) PA_TO_VA(page_to_pa(source_page)) + size_to_read, 0,
329	                       PAGE_SIZE - size_to_read);
330	            }
331	
332	            disable_interrupts();
333	            lock_vm_cache();
334	            source_page->busy = 0;
335	            break;
336	        }
337	
338	        // Otherwise scan the next cache
339	        is_cow_page = 1;
340	
341	        if (cache == area->cache)
342	        {
343	            // Insert a dummy page in the top level cache to catch collided faults.
344	            dummy_page = vm_allocate_page();
345	            dummy_page->busy = 1;
346	            insert_cache_page(cache, cache_offset, dummy_page);
347	        }
348	    }
349	
350	    if (source_page == 0)
351	    {
352	        assert(dummy_page != 0);
353	
354	        VM_DEBUG("source page was not found, use empty page\n");
355	
356	        // No page found, just use the dummy page
357	        dummy_page->busy = 0;
358	        source_page = dummy_page;
359	    }
360	    else if (is_cow_page)
361	    {
362	        // is_cow_page means source_page belongs to another cache.
363	        assert(dummy_page != 0);
364	        if (is_store)
365	        {
366	            // The dummy page have the contents of the source page copied into it,
367	            // and will be inserted into the top cache (it's not really a dummy page
368	            // any more).
369	            memcpy((void*) PA_TO_VA(page_to_pa(dummy_page)),
370	                (void*) PA_TO_VA(page_to_pa(source_page)),
371	                PAGE_SIZE);
372	            VM_DEBUG("write copy page va %08x dest pa %08x source pa %08x\n",
373	                address, page_to_pa(dummy_page), page_to_pa(source_page));
374	            source_page = dummy_page;
375	            dummy_page->busy = 0;
376	        }
377	        else
378	        {
379	            // We will map in the read-only page from the source cache.
380	            // Remove the dummy page from this cache (we do not insert
381	            // the page into this cache, because we don't own it page).
382	            remove_cache_page(dummy_page);
383	            dec_page_ref(dummy_page);
384	
385	            VM_DEBUG("mapping read-only source page va %08x pa %08x\n", address,
386	                page_to_pa(source_page));
387	        }
388	    }
389	
390	    assert(source_page != 0);
391	
392	    // Grab a ref because we are going to map this page
393	    inc_page_ref(source_page);
394	
395	    unlock_vm_cache();
396	    restore_interrupts(old_flags);
397	
398	    // XXX busy wait for page to finish loading
399	    while (source_page->busy)
400	        reschedule();
401	
402	    if (is_store)
403	        source_page->dirty = 1; // XXX Locking?
404	
405	    // It's possible two threads will fault on the same VA and end up mapping
406	    // the page twice. This is fine, because the code above ensures it will
407	    // be the same page.
408	    page_flags = PAGE_PRESENT;
409	
410	    // If the page is clean, we will mark it not writable. This will fault
411	    // on the next write, allowing us to update the dirty flag.
412	    if ((area->flags & AREA_WRITABLE) != 0 && (source_page->dirty || is_store))
413	        page_flags |= PAGE_WRITABLE;
414	
415	    if (area->flags & AREA_EXECUTABLE)
416	        page_flags |= PAGE_EXECUTABLE;
417	
418	    if (space == &kernel_address_space)
419	        page_flags |= PAGE_SUPERVISOR | PAGE_GLOBAL;
420	
421	    vm_map_page(space->translation_map, address, page_to_pa(source_page)
422	        | page_flags);
423	
424	    return 1;
425	}
