21	
22	void *slab_alloc(struct slab_allocator *sa)
23	{
24	    void *object = 0;
25	    int old_flags;
26	
27	    old_flags = acquire_spinlock_int(&sa->lock);
28	    if (sa->free_list)
29	    {
30	        // Grab freed object
31	        object = sa->free_list;
32	        sa->free_list = *((void**) object);
33	    }
34	    else
35	    {
36	        // If there is no wilderness, or the slab is full, create a new
37	        // wilderness slab
38	        if (sa->wilderness_slab == 0
39	                || sa->wilderness_offset + sa->object_size > sa->slab_size)
40	        {
41	            sa->wilderness_slab = kmalloc(sa->slab_size);
42	            sa->wilderness_offset = 0;
43	        }
44	
45	        object = (void*)((char*) sa->wilderness_slab + sa->wilderness_offset);
46	        sa->wilderness_offset += sa->object_size;
47	    }
48	
49	    release_spinlock_int(&sa->lock, old_flags);
50	
51	    return object;
52	}
53	
54	void slab_free(struct slab_allocator *sa, void *object)
55	{
56	    int old_flags;
57	
58	    old_flags = acquire_spinlock_int(&sa->lock);
59	    *((void**) object) = sa->free_list;
60	    sa->free_list = object;
61	    release_spinlock_int(&sa->lock, old_flags);
62	}
