18	#include "libc.h"
19	#include "registers.h"
20	#include "thread.h"
21	#include "trap.h"
22	#include "vm_address_space.h"
23	
24	struct interrupt_frame
25	{
26	    unsigned int gpr[32];
27	    unsigned int pc;
28	    unsigned int flags;
29	    unsigned int subcycle;
30	};
31	
32	void dump_interrupt_frame(int trap_cause, unsigned int trap_address,
33	    const struct interrupt_frame*);
34	extern int handle_syscall(int index, int arg0, int arg1, int arg2, int arg3, int arg4,
35	                          int arg5);
36	
37	static const char *TRAP_NAMES[] =
38	{
39	    "reset",
40	    "Illegal Instruction",
41	    "Privileged Op",
42	    "Interrupt",
43	    "Syscall",
44	    "Unaligned Access",
45	    "Page Fault",
46	    "TLB Miss",
47	    "Illegal Store",
48	    "Illegal Supervisor Page Access",
49	    "Page Non Executable"
50	};
51	
52	static interrupt_handler_t handlers[NUM_INTERRUPTS];
53	static unsigned int enabled_interrupts[MAX_HW_THREADS];
54	
55	// These are set by the user_copy routine.
56	unsigned int fault_handler[MAX_HW_THREADS];
57	
58	void unmask_interrupt(int interrupt)
59	{
60	    int hwthid = current_hw_thread();
61	    enabled_interrupts[hwthid] |= 1 << interrupt;
62	    __builtin_nyuzi_write_control_reg(CR_INTERRUPT_ENABLE, enabled_interrupts[hwthid]);
63	}
64	
65	void register_interrupt_handler(int interrupt, interrupt_handler_t handler)
66	{
67	    // XXX lock
68	    handlers[interrupt] = handler;
69	    unmask_interrupt(interrupt);
70	}
71	
72	static void handle_interrupt()
73	{
74	    unsigned int interrupt_bitmap = __builtin_nyuzi_read_control_reg(CR_INTERRUPT_PENDING);
75	
76	    while (interrupt_bitmap)
77	    {
78	        int next_int = __builtin_ctz(interrupt_bitmap);
79	        interrupt_bitmap &= ~(1 << next_int);
80	        if (handlers[next_int] == 0)
81	        {
82	            kprintf("No handler for interrupt %d", next_int);
83	            panic("STOPPING");
84	        }
85	
86	        (*handlers[next_int])();
87	    }
88	}
89	
90	void ack_interrupt(int interrupt)
91	{
92	    __builtin_nyuzi_write_control_reg(CR_INTERRUPT_ACK, 1 << interrupt);
93	}
94	
95	static void __attribute__((noreturn)) bad_fault(int trap_cause, unsigned int trap_address,
96	    struct interrupt_frame *frame)
97	{
98	    if (frame->flags & FLAG_SUPERVISOR_EN)
99	    {
100	        kprintf("Invalid kernel page fault thread %d\n", current_thread()->id);
101	        dump_interrupt_frame(trap_cause, trap_address, frame);
102	        panic("stopping");
103	    }
104	    else
105	    {
106	        // User space crash. Kill thread. Should kill entire process,
107	        // but need signals/APCs to do that.
108	        kprintf("user space thread %d crashed\n", current_thread()->id);
109	        dump_interrupt_frame(trap_cause, trap_address, frame);
110	        thread_exit(1);
111	    }
112	}
113	
114	void handle_trap(struct interrupt_frame *frame)
115	{
116	    unsigned int address;
117	    int syscall_index;
118	    int trap_cause = __builtin_nyuzi_read_control_reg(CR_TRAP_CAUSE);
119	
120	    switch (trap_cause & 0xf)
121	    {
122	        case TT_PAGE_FAULT:
123	        case TT_ILLEGAL_STORE:
124	            address = __builtin_nyuzi_read_control_reg(CR_TRAP_ADDR);
125	            enable_interrupts();
126	            if (!handle_page_fault(address, (trap_cause & 0x10) != 0))
127	            {
128	                // Jump to user_copy fault handler if set
129	                if (fault_handler[current_hw_thread()] != 0)
130	                    frame->pc = fault_handler[current_hw_thread()];
131	                else
132	                    bad_fault(trap_cause, address, frame);
133	            }
134	
135	            disable_interrupts();
136	            break;
137	
138	        case TT_SYSCALL:
139	            // Enable interrupts
140	            syscall_index = __builtin_nyuzi_read_control_reg(CR_SYSCALL_INDEX);
141	            enable_interrupts();
142	            frame->gpr[0] = handle_syscall(syscall_index, frame->gpr[0],
143	                                           frame->gpr[1], frame->gpr[2],
144	                                           frame->gpr[3], frame->gpr[4],
145	                                           frame->gpr[5]);
146	
147	            frame->pc += 4;    // Next instruction
148	            disable_interrupts();
149	            break;
150	
151	        case TT_INTERRUPT:
152	            handle_interrupt();
153	            break;
154	
155	        default:
156	            bad_fault(trap_cause, 0, frame);
157	    }
158	}
159	
160	void dump_interrupt_frame(int trap_cause, unsigned int trap_address,
161	    const struct interrupt_frame *frame)
162	{
163	    int reg;
164	    int trap_type = trap_cause & 0xf;
165	
166	    if (trap_type <= TT_NOT_EXECUTABLE)
167	    {
168	        kprintf("%s ", TRAP_NAMES[trap_type]);
169	        if (trap_type == TT_UNALIGNED_ACCESS || trap_type == TT_PAGE_FAULT
170	                || trap_type == TT_TLB_MISS || trap_type == TT_ILLEGAL_STORE
171	                || trap_type == TT_SUPERVISOR_ACCESS)
172	        {
173	            kprintf("@%08x %s %s\n", trap_address,
174	                (trap_cause & 0x20) ? "dcache" : "icache",
175	                (trap_cause & 0x10) ? "store" : "load");
176	        }
177	    }
178	    else
179	        kprintf("Unknown trap cause %02x\n", trap_cause);
180	
181	    kprintf("REGISTERS\n");
182	    for (reg = 0; reg < 32; reg++)
183	    {
184	        if (reg < 10)
185	            kprintf(" "); // Align single digit numbers
186	
187	        kprintf("s%d %08x ", reg, frame->gpr[reg]);
188	        if (reg % 8 == 7)
189	            kprintf("\n");
190	    }
191	
192	    kprintf("pc %08x ", frame->pc);
193	    kprintf("Flags: ");
194	    if (frame->flags & 1)
195	        kprintf("I");
196	
197	    if (frame->flags & 2)
198	        kprintf("M");
199	
200	    if (frame->flags & 4)
201	        kprintf("S");
202	
203	    kprintf(" (%02x)\n\n", frame->flags);
204	}
