38	void __attribute__((noreturn)) kernel_main(unsigned int _memory_size)
39	{
40	    struct vm_translation_map *init_map;
41	    struct process *init_proc;
42	
43	    vm_page_init(_memory_size);
44	    init_map = vm_translation_map_init();
45	    boot_init_heap((char*) KERNEL_HEAP_BASE + PAGE_STRUCTURES_SIZE(_memory_size));
46	    vm_address_space_init(init_map);
47	    bootstrap_vm_cache();
48	    bool_init_kernel_process();
49	    boot_init_thread();
50	
51	    // Start other threads
52	    __builtin_nyuzi_write_control_reg(CR_RESUME_THREAD, 0xffffffff);
53	
54	    spawn_kernel_thread("Grim Reaper", grim_reaper, 0);
55	
56	    init_proc = exec_program("program.elf");
57	
58	    // Idle task
59	    for (;;)
60	    {
61	        if (list_is_empty(&init_proc->thread_list))
62	        {
63	            kprintf("init process has exited, shutting down\n");
64	            __builtin_nyuzi_write_control_reg(CR_SUSPEND_THREAD, 0xffffffff);
65	        }
66	
67	        reschedule();
68	    }
69	}
